import React, { useState, useEffect } from "react";
import axios from "axios";

export default function WeatherForecast({ submittedCity }) {
  const [loaded, setLoaded] = useState(false);
  const [forecast, setForecast] = useState(null);

  function handleResponse(response) {
    setForecast(response.data.daily);
    setLoaded(true);
  }

  useEffect(() => {
    if (submittedCity) {
      let apiKey = "39a3014fd34afe90bc14c4tc7oed280d";
      let apiUrl = `https://api.openweathermap.org/data/2.5/onecall?q=${submittedCity}&appid=${apiKey}&units=metric`;

      axios.get(apiUrl).then(handleResponse);
    }
  }, [submittedCity]);

  if (!loaded) {
    return "Loading forecast...";
  }

  return (
    <div className="WeatherForecast">
      {forecast.map(function (dailyForecast, index) {
        if (index < 5) {
          return (
            <div key={index}>
              <p>{Math.round(dailyForecast.temp.day)}°C</p>
            </div>
          );
        } else {
          return null;
        }
      })}
    </div>
  );
}
